using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Confidence { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer
{
    private readonly MLContext _mlContext = new(seed: 42);
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<TicketModelTrainer> _logger;

    // Stores label names in score-array order after training
    public string[] CategoryLabels { get; private set; } = [];

    public TicketModelTrainer(ILogger<TicketModelTrainer> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "ticket_model.zip");
    }

    public string TrainAndEvaluate()
    {
        _logger.LogInformation("Loading training data from {Path}", _dataPath);

        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        _logger.LogInformation("Evaluating model on test set...");
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("  Macro Accuracy:  {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  Micro Accuracy:  {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  Log Loss:        {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("  Log Loss (red.): {LogLossReduction:F4}", metrics.LogLossReduction);

        foreach (var row in metrics.PerClassLogLoss.Select((value, i) => (value, i)))
        {
            _logger.LogInformation("  Class {Index} Log Loss: {Loss:F4}", row.i, row.value);
        }

        _logger.LogInformation("Confusion matrix:\n{Matrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        // Extract category label ordering from the trained model's key-value mapping
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        var labelColumn = predictions.Schema["PredictedLabel"];
        // The label metadata is on the "Label" key column
        var labelKeyColumn = predictions.Schema["Label"];
        labelKeyColumn.GetKeyValues(ref labelBuffer);
        CategoryLabels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

        _mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return _modelPath;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class PredictController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly string[] _categoryLabels;

    public PredictController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        IConfiguration configuration)
    {
        _predictionPool = predictionPool;
        _categoryLabels = configuration.GetSection("ML:CategoryLabels").Get<string[]>() ?? [];
    }

    [HttpPost]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }
}

