            .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        _logger.LogInformation("Evaluating model on test set...");
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("  Macro Accuracy:  {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  Micro Accuracy:  {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  Log Loss:        {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("  Log Loss (red.): {LogLossReduction:F4}", metrics.LogLossReduction);

        foreach (var row in metrics.PerClassLogLoss.Select((value, i) => (value, i)))
        {
            _logger.LogInformation("  Class {Index} Log Loss: {Loss:F4}", row.i, row.value);
        }

        _logger.LogInformation("Confusion matrix:\n{Matrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        // Extract category label ordering from the trained model's key-value mapping
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        var labelColumn = predictions.Schema["PredictedLabel"];
        // The label metadata is on the "Label" key column
        var labelKeyColumn = predictions.Schema["Label"];
        labelKeyColumn.GetKeyValues(ref labelBuffer);
        CategoryLabels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

        _mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return _modelPath;
    }
}

